export function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
	const rows = grid.length;
	if (rows === 0) return null;
	const cols = grid[0].length;

	const startX = start[0];
	const startY = start[1];
	const endX = end[0];
	const endY = end[1];

	// Check if start or end are obstacles
	if (grid[startY][startX] === 1 || grid[endY][endX] === 1) {
		return null;
	}

	// Priority Queue: stores [f_score, x, y]
	// We use an array and sort it to simulate a min-heap for simplicity in this context.
	// In a production environment, a proper MinHeap implementation would be used for O(log N) extraction.
	const openSet: [number, number, number][] = [[0, startX, startY]]; // [f_score, x, y]

	// gScore: stores the cost of the cheapest path from start to that node currently known.
	const gScore = new Map<string, number>();
	gScore.set(`${startX},${startY}`, 0);

	// cameFrom: stores the previous node in the optimal path.
	const cameFrom = new Map<string, [number, number]>();

	// Heuristic function (Manhattan distance)
	const heuristic = (x: number, y: number) => Math.abs(x - endX) + Math.abs(y - endY);

	while (openSet.length > 0) {
		// 1. Find the node with the lowest f_score (Simulate Min-Heap extraction)
		openSet.sort((a, b) => a[0] - b[0]);
		const [fScore, currentX, currentY] = openSet.shift()!;
		const currentKey = `${currentX},${currentY}`;

		// Optimization: If we reached the end
		if (currentX === endX && currentY === endY) {
			// Reconstruct path (optional, we only need length)
			let totalDistance = 0;
			let current = { x: endX, y: endY };
			while (cameFrom.has(`${current.x},${current.y}`)) {
				const prev = cameFrom.get(`${current.x},${current.y}`)!;
				totalDistance++;
				current = prev;
			}
			return totalDistance;
		}

		// 2. Explore neighbors (4 directions)
		const neighbors = [
			[currentX + 1, currentY],
			[currentX - 1, currentY],
			[currentX, currentY + 1],
			[currentX, currentY - 1],
		];

		for (const [nextX, nextY] of neighbors) {
			// Check bounds
			if (nextX >= 0 && nextX < cols && nextY >= 0 && nextY < rows) {
				// Check if blocked (obstacle)
				if (grid[nextY][nextX] === 1) {
					continue;
				}

				const nextKey = `${nextX},${nextY}`;
				const tentativeGScore = gScore.get(currentKey)! + 1;

				// Check if this path to the neighbor is better than any previous one
				if (!gScore.has(nextKey) || tentativeGScore < gScore.get(nextKey)!) {
					// This is the best path so far. Record it.
					cameFrom.set(nextKey, [currentX, currentY]);
					gScore.set(nextKey, tentativeGScore);

					const fScore = tentativeGScore + heuristic(nextX, nextY);

					// Add or update in the open set
					openSet.push([fScore, nextX, nextY]);
				}
			}
		}
	}

	// If the loop finishes without reaching the end
	return null;
}

export function binarySearchBoundary(values: number[], target: number): number {
	let left = 0;
	let right = values.length - 1;
	let result = -1;

	while (left <= right) {
		const mid = Math.floor((left + right) / 2);

		if (values[mid] === target) {
			result = mid;
			right = mid - 1; // Try to find the first occurrence in the left half
		} else if (values[mid] < target) {
			left = mid + 1;
		} else {
			right = mid - 1;
		}
	}

	return result;
}

