export function dijkstraShortestPath(nodeCount: number, edges: readonly [number, number, number][], start: number, end: number): number | null {
	if (nodeCount <= 0) {
		return null;
	}

	// 1. Build Adjacency List
	// adj[u] = [{node: v, weight: w}, ...]
	const adj: Record<number, { node: number, weight: number }[]> = {};
	for (let i = 0; i < nodeCount; i++) {
		adj[i] = [];
	}

	for (const [u, v, weight] of edges) {
		if (u >= 0 && u < nodeCount && v >= 0 && v < nodeCount) {
			adj[u].push({ node: v, weight: weight });
		}
	}

	// 2. Initialize Distances
	const distances: number[] = new Array(nodeCount).fill(Infinity);
	distances[start] = 0;

	// 3. Priority Queue Simulation (using an array of [distance, node])
	// We will use a simple array and find the minimum element in each iteration,
	// simulating a min-heap for simplicity in this context.
	const priorityQueue: [number, number][] = [[0, start]];

	while (priorityQueue.length > 0) {
		// Find the node with the minimum distance (Simulate extract_min)
		let minIndex = 0;
		for (let i = 1; i < priorityQueue.length; i++) {
			if (priorityQueue[i][0] < priorityQueue[minIndex][0]) {
				minIndex = i;
			}
		}

		const [dist, u] = priorityQueue.splice(minIndex, 1)[0];

		// Optimization: If we reached the end node, return the distance
		if (u === end) {
			return dist;
		}

		// If the extracted distance is greater than the recorded distance, skip (stale entry)
		if (dist > distances[u]) {
			continue;
		}

		// 4. Relaxation
		for (const edge of adj[u]) {
			const v = edge.node;
			const weight = edge.weight;

			const newDist = distances[u] + weight;

			if (newDist < distances[v]) {
				distances[v] = newDist;
				priorityQueue.push([newDist, v]);
			}
		}
	}

	// If the loop finishes and we haven't returned, the end node is unreachable
	return distances[end] === Infinity ? null : distances[end];
}

export function fftBigintMultiplyDigitArrays(a: number[], b: number[]): number[] {
	const n = a.length;
	const m = b.length;
	const resultLength = n + m - 1;

	// 1. Determine FFT size N (next power of 2 >= resultLength)
	let N = 1;
	while (N < resultLength) {
		N *= 2;
	}

	// Helper function for complex numbers (for FFT)
	interface Complex {
		re: number;
		im: number;
	}

	// 2. Pad and convert to complex arrays
	let fa: Complex[] = new Array(N).fill(0).map(() => ({ re: 0, im: 0 }));
	let fb: Complex[] = new Array(N).fill(0).map(() => ({ re: 0, im: 0 }));

	for (let i = 0; i < n; i++) {
		fa[i].re = a[i];
	}
	for (let i = 0; i < m; i++) {
		fb[i].re = b[i];
	}

	// --- FFT Implementation (Cooley-Tukey) ---

	function fft(arr: Complex[], inverse: boolean): void {
		const N_fft = arr.length;
		for (let i = 1; i < N_fft; i++) {
			let angle = 2 * Math.PI * i / N_fft * (inverse ? -1 : 1);
			let wre = Math.cos(angle);
			let wime = Math.sin(angle);

			let u = arr[i];
			let v = arr[i - N_fft];

			arr[i] = {
				re: arr[i].re + wre * v.re - wime * v.im,
				im: arr[i].im + wre * v.im + wime * v.re,
			};
			arr[i - N_fft] = {
				re: arr[i].re - wre * v.re + wime * v.im,
				im: arr[i].im - wre * v.im - wime * v.re,
			};
		}

		if (inverse) {
			for (let i = 0; i < N_fft; i++) {
				arr[i].re /= N_fft;
				arr[i].im /= N_fft;
			}
		}
	}

	// 3. Perform FFT on padded arrays
	fft(fa, false);
	fft(fb, false);

	// 4. Pointwise Multiplication
	let fc: Complex[] = new Array(N);
	for (let i = 0; i < N; i++) {
		fc[i] = {
			re: fa[i].re * fb[i].re - fa[i].im * fb[i].im,
			im: fa[i].re * fb[i].im + fa[i].im * fb[i].re,
		};
	}

	// 5. Perform Inverse FFT
	fft(fc, true);

	// 6. Extract and handle carries
	// The result is the convolution of the digit arrays.
	// We need to handle the result, which is a large array of coefficients.

	// Initialize result array for carries
	let result = new Array(resultLength + 1);
	let carry = 0;

	// The convolution result is stored in fc.re (the real part of the IFFT result).
	// We process the coefficients from the lowest index (which corresponds to the lowest power of x).

	for (let i = 0; i < resultLength; i++) {
		// The result of the convolution is fc[i].re. We must round it to the nearest integer.
		let currentSum = Math.round(fc[i].re);

		// Add the previous carry
		let total = currentSum + carry;

		// Store the digit (remainder)
		result[resultLength - 1 - i] = total % 10;

		// Calculate the new carry
		carry = Math.floor(total / 10);
	}

	// Handle final carry
	if (carry > 0) {
		result[0] = carry;
	}

	// The result array is currently reversed due to the way we indexed the convolution result.
	// We need to reverse it back to big-endian (MSD first).
	return result.reverse();
}

export function fibonacci(n: number): number {
	if (n === 0) {
		return 0;
	}
	if (n === 1) {
		return 1;
	}

	let a = 0; // F(i-2)
	let b = 1; // F(i-1)

	for (let i = 2; i <= n; i++) {
		const next = a + b;
		a = b;
		b = next;
	}

	return b;
}

