export function integerBreakMaxProduct(n: number): number {
	if (n === 2) {
		return 1;
	}
	if (n === 3) {
		return 2;
	}

	const q = Math.floor(n / 3);
	const r = n % 3;

	if (r === 0) {
		// n = 3q. Max product is 3^q
		return Math.pow(3, q);
	} else if (r === 1) {
		// n = 3q + 1. Max product is 4 * 3^(q-1)
		return 4 * Math.pow(3, q - 1);
	} else { // r === 2
		// n = 3q + 2. Max product is 2 * 3^q
		return 2 * Math.pow(3, q);
	}
}

export function longestCommonSubsequence(a: string, b: string): number {
	const m = a.length;
	const n = b.length;

	// dp[i][j] will store the length of LCS of a[0..i-1] and b[0..j-1]
	const dp: number[][] = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

	for (let i = 1; i <= m; i++) {
		for (let j = 1; j <= n; j++) {
			if (a[i - 1] === b[j - 1]) {
				dp[i][j] = dp[i - 1][j - 1] + 1;
			} else {
				dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
			}
		}
	}

	return dp[m][n];
}

