export function longestSubstringNoRepeat(input: string): number {
	if (input.length === 0) {
		return 0;
	}

	let left = 0;
	let maxLength = 0;
	// Map to store the last seen index of each character
	const charIndexMap = new Map<string, number>();

	for (let right = 0; right < input.length; right++) {
		const char = input[right];

		if (charIndexMap.has(char)) {
			const lastIndex = charIndexMap.get(char)!;
			// If the last occurrence is within the current window [left, right-1],
			// we must move the left pointer past it.
			if (lastIndex >= left) {
				left = lastIndex + 1;
			}
		}

		// Update the last seen index for the current character
		charIndexMap.set(char, right);

		// Calculate the current window length and update max length
		maxLength = Math.max(maxLength, right - left + 1);
	}

	return maxLength;
}

export function lruCache(capacity: number, operations: readonly (readonly ['get' | 'put', number, number?])[]): (number | null)[] {
	const cache = new Map<number, number>();
	const results: (number | null)[] = [];

	for (const op of operations) {
		const type = op[0];
		const key = op[1];

		if (type === 'get') {
			if (cache.has(key)) {
				const value = cache.get(key)!;
				// Update usage: delete and re-insert to move to MRU position
				cache.delete(key);
				cache.set(key, value);
				results.push(value);
			} else {
				results.push(null);
			}
		} else if (type === 'put') {
			const value = op[2]!;

			if (cache.has(key)) {
				// Update existing item (MRU update)
				cache.delete(key);
				cache.set(key, value);
			} else {
				// New item
				if (cache.size >= capacity) {
					// Evict LRU (the first item in the Map iteration order)
					const lruKey = cache.keys().next().value;
					cache.delete(lruKey);
				}
				cache.set(key, value);
			}
		}
	}

	return results;
}

