export function numberOfIslands(grid: string[][]): number {
	if (!grid || grid.length === 0) {
		return 0;
	}

	const R = grid.length;
	const C = grid[0].length;
	let islandCount = 0;

	// Helper function for BFS flood-fill
	const bfs = (startR: number, startC: number): void => {
		const queue: [number, number][] = [[startR, startC]];
		grid[startR][startC] = '0'; // Mark as visited

		const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

		while (queue.length > 0) {
			const [r, c] = queue.shift()!;

			for (const [dr, dc] of directions) {
				const nr = r + dr;
				const nc = c + dc;

				if (nr >= 0 && nr < R && nc >= 0 && nc < C && grid[nr][nc] === '1') {
					grid[nr][nc] = '0'; // Sink the land
					queue.push([nr, nc]);
				}
			}
		}
	};

	for (let r = 0; r < R; r++) {
		for (let c = 0; c < C; c++) {
			if (grid[r][c] === '1') {
				islandCount++;
				bfs(r, c);
			}
		}
	}

	return islandCount;
}

