export function quickselectKthSmallest(values: number[], k: number): number {
	if (k < 1 || k > values.length) {
		throw new Error('k is out of bounds');
	}

	// Quickselect works by finding the element that would be at index k-1 if sorted.
	let left = 0;
	let right = values.length - 1;
	let targetIndex = k - 1;

	while (left <= right) {
		// Choose a pivot index (using the middle element for simplicity)
		let pivotIndex = Math.floor((left + right) / 2);

		// Move pivot to the end (or start) for partitioning
		[values[pivotIndex], values[right]] = [values[right], values[pivotIndex]];

		// Partitioning step (Lomuto partition scheme adapted)
		let i = left;
		for (let j = left; j < right; j++) {
			if (values[j] <= values[right]) {
				[values[i], values[j]] = [values[j], values[i]];
				i++;
			}
		}
		// Place the pivot (which is currently at values[right]) into its final sorted position
		[values[i], values[right]] = [values[right], values[i]];

		// i is the final position of the pivot
		pivotIndex = i;


		if (pivotIndex === targetIndex) {
			return values[pivotIndex];
		} else if (pivotIndex < targetIndex) {
			// The target is in the right subarray
			left = pivotIndex + 1;
		} else {
			// The target is in the left subarray
			right = pivotIndex - 1;
		}
	}

	// This line should theoretically not be reached if k is valid
	throw new Error('Quickselect failed to find the element.');
}

