export function topKFrequent(values: number[], k: number): number[] {
	const frequencyMap = new Map<number, number>();

	// 1. Count frequencies
	for (const value of values) {
		frequencyMap.set(value, (frequencyMap.get(value) || 0) + 1);
	}

	// 2. Convert map entries to an array and sort by frequency (descending)
	const sortedEntries = Array.from(frequencyMap.entries()).sort((a, b) => b[1] - a[1]);

	// 3. Extract the top k elements
	const result: number[] = [];
	for (let i = 0; i < k && i < sortedEntries.length; i++) {
		result.push(sortedEntries[i][0]);
	}

	return result;
}

export function toyRsaBigint(p: bigint, q: bigint, e: bigint, message: bigint): {publicKey: {n: bigint; e: bigint}; privateKey: {n: bigint; d: bigint}; cipher: bigint; decrypted: bigint} {
	// Helper function for modular inverse using Extended Euclidean Algorithm
	const modInverse = (a: bigint, m: bigint): bigint => {
		let m0 = m;
		let x0 = 0n;
		let x1 = 1n;

		if (m === 1n) return 0n;

		while (a > 1n) {
			let q = a / m;
			let t = m;
			m = a % m;
			a = t;
			t = x0;
			x0 = x1 - q * x0;
			x1 = t;
		}

		if (x1 < 0n) {
			x1 += m0;
		}
		return x1;
	};

	// 1. Calculate n (Modulus)
	const n = p * q;

	// 2. Calculate phi(n)
	const phi = (p - 1n) * (q - 1n);

	// 3. Calculate d (Private Exponent) using modular inverse
	// d = e^(-1) mod phi
	const d = modInverse(e, phi);

	// 4. Calculate Public Key and Private Key
	const publicKey = { n: n, e: e };
	const privateKey = { n: n, d: d };

	// 5. Encryption: c = m^e mod n
	// Note: BigInt exponentiation requires the built-in operator ** and %
	let cipher = (message ** e) % n;

	// 6. Decryption: m' = c^d mod n
	let decrypted = (cipher ** d) % n;

	return {
		publicKey: publicKey,
		privateKey: privateKey,
		cipher: cipher,
		decrypted: decrypted
	};
}

