export function unionFindConnectedComponentsOnline(n: number, operations: readonly [number, number][]): number[] {
	if (n <= 0) {
		return [];
	}

	// Initialize Union-Find structure
	const parent: number[] = Array.from({ length: n }, (_, i) => i);
	let numComponents = n;

	// Find operation with path compression
	const find = (i: number): number => {
		if (parent[i] === i) {
			return i;
		}
		parent[i] = find(parent[i]);
		return parent[i];
	};

	// Union operation
	const union = (i: number, j: number): boolean => {
		let rootI = find(i);
		let rootJ = find(j);

		if (rootI !== rootJ) {
			parent[rootJ] = rootI;
			numComponents--;
			return true;
		}
		return false;
	};

	const results: number[] = [];

	for (const [u, v] of operations) {
		// Ensure nodes are within bounds (optional, but good practice)
		if (u >= n || v >= n || u < 0 || v < 0) {
			// Handle invalid input if necessary, though typically assumed valid in benchmarks
			continue;
		}

		// Perform the union
		union(u, v);

		// Record the current number of connected components
		results.push(numComponents);
	}

	return results;
}

export function validParentheses(input: string): boolean {
	const stack: string[] = [];
	const map: { [key: string]: string } = {
		')': '(',
		']': '[',
		'}': '{'
	};

	for (const char of input) {
		if (char === '(' || char === '[' || char === '{') {
			stack.push(char);
		} else if (char === ')' || char === ']' || char === '}') {
			if (stack.length === 0) {
				return false;
			}
			const lastOpen = stack.pop();
			if (lastOpen !== map[char]) {
				return false;
			}
		}
	}

	return stack.length === 0;
}

