export function avlTreeInsertRebalance(values: number[]): {value: number; height: number; left: any; right: any} | null {
	// Internal Node structure definition (using the provided signature structure)
	type AVLNode = {value: number; height: number; left: AVLNode | null; right: AVLNode | null};

	// Helper function to get height safely
	const getHeight = (node: AVLNode | null): number => {
		return node ? node.height : 0;
	};

	// Helper function to update height
	const updateHeight = (node: AVLNode): AVLNode => {
		node.height = 1 + Math.max(getHeight(node.left), getHeight(node.right));
		return node;
	};

	// Helper function to get balance factor
	const getBalanceFactor = (node: AVLNode | null): number => {
		if (!node) return 0;
		return getHeight(node.left) - getHeight(node.right);
	};

	// Helper function for right rotation
	const rotateRight = (y: AVLNode): AVLNode => {
		const x = y.left;
		const T2 = x.right;

		// Perform rotation
		x.right = y;
		y.left = T2;

		// Update heights
		y = updateHeight(y);
		x = updateHeight(x);

		return x;
	};

	// Helper function for left rotation
	const rotateLeft = (x: AVLNode): AVLNode => {
		const y = x.right;
		const T2 = y.left;

		// Perform rotation
		y.left = x;
		x.right = T2;

		// Update heights
		x = updateHeight(x);
		y = updateHeight(y);

		return y;
	};

	// Recursive insertion function
	const insert = (node: AVLNode | null, value: number): AVLNode | null => {
		// 1. Standard BST Insertion
		if (node === null) {
			return { value, height: 1, left: null, right: null };
		}

		if (value < node.value) {
			node.left = insert(node.left, value);
		} else if (value > node.value) {
			node.right = insert(node.right, value);
		} else {
			// Duplicate values are ignored
			return node;
		}

		// 2. Update height
		node = updateHeight(node);

		// 3. Get balance factor
		const balance = getBalanceFactor(node);

		// 4. Rebalance (Left Heavy)
		if (balance > 1) {
			// Left-Right Case (LR)
			if (value > node.left!.value) {
				node.left = rotateLeft(node.left!);
			}
			// Left-Left Case (LL)
			node = rotateRight(node);
		}

		// 5. Rebalance (Right Heavy)
		if (balance < -1) {
			// Right-Left Case (RL)
			if (value < node.right!.value) {
				node.right = rotateRight(node.right!);
			}
			// Right-Right Case (RR)
			node = rotateLeft(node);
		}

		return node;
	};

	let root: AVLNode | null = null;

	// Insert all values
	for (const value of values) {
		root = insert(root, value);
	}

	return root;
}

