	const bitArray: boolean[] = new Array(size).fill(false);

	// Helper function for simple string hashing (DJB2-like approach)
	const stringToHash = (str: string): number => {
		let hash = 5381;
		for (let i = 0; i < str.length; i++) {
			hash = (hash * 33) ^ str.charCodeAt(i);
		}
		// Ensure the result is positive and within reasonable bounds
		return Math.abs(hash);
	};

	// 2. Insert words
	for (const word of wordsToAdd) {
		const hashValue = stringToHash(word);

		for (let i = 0; i < hashCount; i++) {
			// Calculate the index using the hash value and the hash count index
			// We use the property: hash(word, i) = (hashValue + i) % size
			const index = (hashValue + i) % size;
			bitArray[index] = true;
		}
	}

	// 3. Answer membership queries
	const results: boolean[] = [];
	for (const query of queries) {
		let isMember = true;

		const queryHashValue = stringToHash(query);

		for (let i = 0; i < hashCount; i++) {
			const index = (queryHashValue + i) % size;
			if (!bitArray[index]) {
				// If any required bit is false, the item is definitely not present
				isMember = false;
				break;
			}
		}
		results.push(isMember);
	}

	return results;
}

