			stack.push(parseFloat(token));
		} else {
			// Token is an operator
			if (stack.length < 2) {
				throw new Error('Invalid RPN expression: insufficient operands');
			}

			const operand2 = stack.pop();
			const operand1 = stack.pop();
			let result: number;

			switch (token) {
				case '+':
					result = operand1 + operand2;
					break;
				case '-':
					result = operand1 - operand2;
					break;
				case '*':
					result = operand1 * operand2;
					break;
				case '/':
					// Division truncates toward zero (standard behavior for JS division)
					result = operand1 / operand2;
					break;
				default:
					throw new Error(`Unknown operator: ${token}`);
			}
			stack.push(result);
		}
	}

	if (stack.length !== 1) {
		throw new Error('Invalid RPN expression: too many operands left');
	}

	return stack[0];
}

export function kLargestElementsInStream(stream: number[], k: number): number[][] {
	const results: number[][] = [];
