export function reverseLinkedListInPlace(head: {value: number; next: any} | null): {value: number; next: any} | null {
	let prev: {value: number; next: any} | null = null;
	let current: {value: number; next: any} | null = head;
	let nextNode: {value: number; next: any} | null;

	while (current !== null) {
		nextNode = current.next;
		current.next = prev;
		prev = current;
		current = nextNode;
	}

	return prev;
}

class TrieNode {
    children: Map<string, TrieNode> = new Map();
    isEndOfWord: boolean = false;
}

class Trie {
    root: TrieNode = new TrieNode();

    insert(word: string): void {
        let node = this.root;
        for (const char of word) {
            if (!node.children.has(char)) {
                node.children.set(char, new TrieNode());
            }
            node = node.children.get(char)!;
        }
        node.isEndOfWord = true;
    }

    findNode(prefix: string): TrieNode | null {
        let node = this.root;
        for (const char of prefix) {
            if (!node.children.has(char)) {
                return null;
            }
            node = node.children.get(char)!;
        }
        return node;
    }

    collectWords(node: TrieNode, currentPrefix: string, results: string[]): void {
        if (node.isEndOfWord) {
            results.push(currentPrefix);
        }

        // Iterate over children keys in lexicographical order
        const sortedChars = Array.from(node.children.keys()).sort();

        for (const char of sortedChars) {
            const child = node.children.get(char)!;
            this.collectWords(child, currentPrefix + char, results);
        }
    }
}

export function trieAutocomplete(words: string[], prefixes: string[]): string[][] {
    const trie = new Trie();

    // 1. Build the Trie
    for (const word of words) {
        trie.insert(word);
    }

    const results: string[][] = [];

    // 2. Process Queries
    for (const prefix of prefixes) {
        const startNode = trie.findNode(prefix);

        if (startNode) {
            const completions: string[] = [];
            // Start collecting words from the found node
            trie.collectWords(startNode, prefix, completions);
            results.push(completions);
        } else {
            // If no words start with this prefix, return an empty array
            results.push([]);
        }
    }

    return results;
}

export function validateBinarySearchTree(root: {value: number; left: any; right: any} | null): boolean {
