	 * @param node The current node being checked.
	 * @param min The minimum allowed value for this subtree.
	 * @param max The maximum allowed value for this subtree.
	 */
	function validate(node: {value: number; left: any; right: any} | null, min: number, max: number): boolean {
		if (node === null) {
			return true;
		}

		// 1. Check if the current node's value is within the allowed range [min, max]
		if (node.value <= min || node.value >= max) {
			return false;
		}

