		const leftValid = validate(node.left, min, node.value);

		// 3. Recursively check the right subtree: values must be > node.value and < max
		const rightValid = validate(node.right, node.value, max);

		return leftValid && rightValid;
	}

	// Start validation with infinite bounds
	return validate(root, Number.NEGATIVE_INFINITY, Number.POSITIVE_INFINITY);
}

