export function easterSunday(year: number): {month: number; day: number} {
	const a = year % 19;
	const b = year % 4;
	const c = year % 7;

	const d = (19 * a + b) % 30;
	const e = (2 * b + 4 * c + 6 * d + a) % 7;
	const f = (3 * d + 4) % 19;
	const g = (b - 4 * d + 19 * a) % 30;
	const h = (11 * f + 11) % 30;

	const month = (19 * a + b + 11 * h - 11) % 12 + 1;
	const day = g + 1;

	return { month: month, day: day };
}

export function getISOWeek(date: Date): {week: number; year: number} {
	const year = date.getUTCFullYear();

	// Create a date object for January 1st of that year (UTC)
	const jan1 = new Date(Date.UTC(year, 0, 1));

	// Calculate the difference in milliseconds between the input date and Jan 1st
	const diffTime = date.getTime() - jan1.getTime();

	// Calculate the number of days elapsed since Jan 1st
	const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

	// ISO week calculation: (days elapsed + 1) / 7
	// We add 1 because the first day (Jan 1st) is day 1 of the year, and we want to count weeks starting from week 1.
	const week = Math.floor((diffDays - 1) / 7) + 1;

	return {week: week, year: year};
}

