export function validateDate(s: string): boolean {
	const parts = s.split('-');

	if (parts.length !== 3) {
		return false;
	}

	const Y = parseInt(parts[0], 10);
	const M = parseInt(parts[1], 10);
	const D = parseInt(parts[2], 10);

	// Basic range check for month and day
	if (M < 1 || M > 12 || D < 1) {
		return false;
	}

	// Determine days in the given month
	let daysInMonth: number;

	// Check for leap year
	const isLeap = (Y % 4 === 0 && Y % 100 !== 0) || (Y % 400 === 0);

	switch (M) {
		case 2: // February
			daysInMonth = isLeap ? 29 : 28;
			break;
		case 4: // April
		case 6: // June
		case 9: // September
		case 11: // November
			daysInMonth = 30;
			break;
		default: // January, March, May, July, August, October, December
			daysInMonth = 31;
			break;
	}

	return D <= daysInMonth;
}

