export function dateInputToIso(input: string): string | null {
	if (!input) {
		return null;
	}

	const parts = input.split('-');
	if (parts.length !== 2) {
		return null;
	}

	const month = parseInt(parts[0], 10);
	const day = parseInt(parts[1], 10);

	if (isNaN(month) || isNaN(day)) {
		return null;
	}

	// Assume current year for conversion
	const year = new Date().getFullYear();

	// Create the date object (Month is 0-indexed)
	const date = new Date(year, month - 1, day);

	// Check if the date object is valid (handles invalid dates like Feb 30)
	if (isNaN(date.getTime())) {
		return null;
	}

	// Format to ISO string (YYYY-MM-DD)
	return date.toISOString().slice(0, 10);
}

