export type Row = Record<string, string | number | boolean | null>;

/**
 * Converts an array of JSON rows into a CSV string.
 * @param rows The array of row objects.
 * @returns The resulting CSV string.
 */
export function jsonToCsv(rows: Row[]): string {
	if (rows.length === 0) {
		return '';
	}

	// Determine headers (keys of the first row)
	const headers = Object.keys(rows[0]);
	const csvHeaders = headers.join(',');

	// Build the CSV string
	const csvRows = [csvHeaders];

	for (const row of rows) {
		const values = headers.map(header => {
			let value = row[header];
			if (value === null) {
				return '';
			}
			// Ensure all values are treated as strings for CSV
			return String(value);
		});
		csvRows.push(values.join(','));
	}

	return csvRows.join('\n');
}

/**
 * Converts a CSV string into an array of JSON rows.
 * Assumes comma delimiter and simple structure.
 * @param csv The input CSV string.
 * @returns An array of Row objects.
 */
export function csvToJson(csv: string): Row[] {
	if (!csv) {
		return [];
	}

	const lines = csv.trim().split('\n').filter(line => line.length > 0);
	if (lines.length === 0) {
		return [];
	}

	// Parse headers
	const headers = lines[0].split(',').map(h => h.trim());
	const result: Row[] = [];

	for (let i = 1; i < lines.length; i++) {
		const values = lines[i].split(',');
		if (values.length !== headers.length) {
			// Skip malformed lines or handle error appropriately
			continue;
		}

		const row: Row = {};
		for (let j = 0; j < headers.length; j++) {
			const header = headers[j];
			let value = values[j].trim();

			// Attempt type coercion
			if (value === '') {
				row[header] = null;
			} else if (!isNaN(Number(value)) && value !== '') {
				// Check if it's a valid number
				row[header] = Number(value);
			} else if (value.toLowerCase() === 'true') {
				row[header] = true;
			} else if (value.toLowerCase() === 'false') {
				row[header] = false;
			} else {
				row[header] = value;
			}
		}
		result.push(row);
	}

	return result;
}

/**
 * Converts an array of JSON rows into an XML string.
 * @param rows The array of row objects.
 * @param rootElement The name of the root XML element.
 * @param rowElement The name of the row XML element.
 * @returns The resulting XML string.
 */
export function jsonToXml(rows: Row[], rootElement: string, rowElement: string): string {
	let xml = '<?xml version="1.0" encoding="UTF-8"?>\n';
	xml += `<${rootElement}>\n`;

	for (const row of rows) {
		xml += `  <${rowElement}>\n`;
		for (const key in row) {
			const value = row[key];
			// Handle nulls by omitting the tag or setting content to empty string
			if (value === null || value === '') {
				// For simplicity in this benchmark, we omit empty/null fields unless explicitly required
				continue;
			}
			xml += `    <${key}>${String(value)}</${key}>\n`;
		}
		xml += `  </${rowElement}>\n`;
	}

	xml += `</${rootElement}>`;
	return xml;
}

/**
