	let decimalFound = false;
	let hasDigits = false;
	let result = 0;
	let currentPowerOfTen = 1;
	let startIndex = 0;

	// 1. Handle optional sign
	if (trimmedS[0] === '-') {
		sign = -1;
		startIndex = 1;
	}

	// 2. Iterate and validate characters
	for (let i = startIndex; i < trimmedS.length; i++) {
		const char = trimmedS[i];

		if (char >= '0' && char <= '9') {
			hasDigits = true;
			const digit = parseInt(char, 10);

			// Accumulate the value
			result += digit * currentPowerOfTen;
			currentPowerOfTen *= 10;

		} else if (char === '.') {
			// Check for multiple decimal points
			if (decimalFound) {
				return null; // More than one decimal point
			}
			decimalFound = true;

			// If we encounter a decimal point, we must ensure there are digits following it.
			// If we are at the end of the string, and only had a decimal point (e.g., "."), it's invalid.
			// We don't update currentPowerOfTen here, as we are not accumulating digits yet.

		} else {
			// Invalid character found
			return null;
		}
	}

	// 3. Final validation
	if (!hasDigits) {
		// This handles cases like ".", "-", or empty strings after trimming (already handled above, but good safety check)
		return null;
	}

	// If we reached here, the structure is valid (digits and at most one decimal point).
	// The result is already calculated based on the accumulation.
	return result * sign;
}

