import axios, { AxiosRequestConfig, AxiosResponse } from 'axios';

// Define the structure for the data returned by the API, based on the parsing logic
interface ApiItem {
	id: string | number;
	label: string;
	meta: Record<string, any>;
}

interface ApiResponse {
	items: ApiItem[];
}

// Global state management (using module scope variables)
let baseURL: string = '';
const defaultHeaders: Record<string, string> = {};

export function configure(options: {
	baseURL?: string;
	headers?: Record<string, string>;
}) {
	baseURL = options.baseURL || '';
	if (options.headers) {
		Object.assign(defaultHeaders, options.headers);
	}
}

export async function get<T>(path: string, params: Record<string, string> = {}): Promise<T> {
	const response = await axios.get<AxiosResponse>(baseURL + path, {
		params,
		headers: defaultHeaders,
	});
	return response.data;
}

export async function post<T>(path: string, body: any, options?: {
	headers?: Record<string, string>;
}): Promise<T> {
	const response = await axios.post<AxiosResponse>(baseURL + path, body, {
		headers: {
			...defaultHeaders,
			...(options?.headers),
		},
	});
	return response.data;
}

export function buildQueryString(params: Record<string, string>): string {
	return Object.entries(params)
		.filter(([, v]) => v !== undefined && v !== null)
		.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
		.join('&');
}

export function parseResponse(raw: AxiosResponse<ApiResponse>): ApiItem[] {
	if (raw && raw.data && Array.isArray(raw.data.items)) {
		return raw.data.items.map(item => ({
			id: item.id,
			label: item.name || item.title || 'Unknown',
			meta: item.meta || {},
		}));
	}
	return [];
}

