class EventBus {
    /**
     * Internal storage for registered events and listeners.
     * @private
     */
    private _events: { [key: string]: { fn: Function, ctx: any, once: boolean }[] } = {};

    /**
     * Registers a listener for an event.
     * @param event The name of the event.
     * @param handler The function to call when the event is emitted.
     * @param context The `this` context for the handler execution. Defaults to the EventBus instance.
     * @returns The EventBus instance.
     */
    on(event: string, handler: Function, context?: any): this {
        if (!this._events[event]) {
            this._events[event] = [];
        }
        this._events[event].push({ fn: handler, ctx: context || this, once: false });
        return this;
    }

    /**
     * Registers a listener that will be called only once.
     * @param event The name of the event.
     * @param handler The function to call when the event is emitted.
     * @param context The `this` context for the handler execution. Defaults to the EventBus instance.
     * @returns The EventBus instance.
     */
    once(event: string, handler: Function, context?: any): this {
        if (!this._events[event]) {
            this._events[event] = [];
        }
        this._events[event].push({ fn: handler, ctx: context || this, once: true });
        return this;
    }

    /**
     * Emits an event, calling all registered listeners.
     * @param event The name of the event to emit.
     * @param args Arguments passed to the handlers.
     * @returns The EventBus instance.
     */
    emit(event: string, ...args: any[]): this {
        const listeners = this._events[event];
        if (!listeners) {
            return this;
        }

        // Iterate over a copy of the listeners to prevent issues if listeners modify the list during iteration
        const listenersToCall = [...listeners];

        for (const listener of listenersToCall) {
            listener.fn.apply(listener.ctx, args);
        }
        return this;
    }

    /**
     * Removes a specific listener for an event.
     * @param event The name of the event.
     * @param handler The specific function reference to remove.
     * @returns The EventBus instance.
     */
    off(event: string, handler: Function): this {
        const listeners = this._events[event];
        if (!listeners) {
            return this;
        }

        // Filter out listeners matching the provided handler reference
        this._events[event] = listeners.filter(listener => listener.fn !== handler);

        // Clean up if no listeners remain
        if (this._events[event].length === 0) {
            delete this._events[event];
        }

        return this;
    }

    /**
     * Clears all registered events and listeners.
     * @returns The EventBus instance.
     */
    clear(): this {
        this._events = {};
        return this;
    }
}

export default new EventBus();

