export function balancedTagNamedBackreference(): RegExp {
	// This regex matches a sequence of tags where the closing tag name
	// is a named backreference to the opening tag name.
	// It handles arbitrary content between the tags ([\s\S]*?) and allows
	// for optional whitespace around the tags.
	return /<(?<name>\w+)>[\s\S]*?<\/\s*<\g<name>>/gs;
}

export function camelCaseSplitRegexp(): RegExp {
	// Splits camelCase and acronym boundaries.
	// 1. (?<=[a-z])(?=[A-Z]): Splits between a lowercase letter and an uppercase letter (e.g., myVar -> my | Var)
	// 2. (?<=[A-Z])(?=[A-Z][a-z]): Splits between an uppercase letter and a subsequent uppercase letter followed by a lowercase letter (e.g., APIKey -> API | Key)
	return /(?<=[a-z])(?=[A-Z])|(?<=[A-Z])(?=[A-Z][a-z])/g;
}

export function containsEmojiUnicodeProperty(): RegExp {
	return /\p{Emoji}/u;
}

export function creditCardRedactionMatch(): RegExp {
	// This regex matches sequences of digits that are typically credit card lengths (13 to 19 digits),
	// allowing for common separators (spaces or hyphens) between groups of digits.
	// This allows for grouping and contiguous matching required for redaction.
	const pattern = /\b(?:\d[ -]*?){13,19}\b/g;
	return pattern;
}

export function cssHexColor(): RegExp {
	// Matches strings starting with # followed by exactly 3, 4, 6, or 8 hexadecimal characters.
	// [0-9a-fA-F] matches any valid hex digit.
	const hexPattern = '[0-9a-fA-F]{3}|[0-9a-fA-F]{4}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8}';
	return new RegExp(`^#${hexPattern}$`);
}

export function ibanFormatEuropeSubset(): RegExp {
	// Pattern breakdown:
	// ^                  Start of string
	// [A-Z]{2}           Country code (2 uppercase letters)
	// \d{2}              Check digits (2 digits)
	// [A-Z0-9]{0,26}     BBAN (Basic Bank Account Number) - Alphanumeric, up to 26 characters
	// $                  End of string
	// Total length: 2 + 2 + 26 = 30 (maximum allowed)
	const regex = /^([A-Z]{2})\d{2}[A-Z0-9]{0,26}$/;
	return regex;
}

export function innermostTagContentNonGreedy(): RegExp {
	// This RegExp extracts content non-greedily between any pair of tags.
	// It assumes the structure is generally <tag>content</tag>
	return /(.*?)(?=<)/g;
}

export function insertThousandsSeparatorsLookahead(n: string): string {
	return n.replace(/\d(?=(\d{3})+(?!\d))/g, "$1,");
}

export function ipv4WithOptionalCidr(): RegExp {
	// Pattern for a single valid octet (0-255, no leading zeros)
	// 250-255: 25[0-5]
	// 200-249: 2[0-4][0-9]
	// 100-199: 1[0-9]{2}
