export type WrapOptions = {
	width?: number;
	lineBreak?: string;
	mode?: 'soft' | 'hard';
	hangingIndent?: string;
	collapseWhitespace?: boolean;
};

export function wordWrap(text: string, options?: WrapOptions): string {
	if (!text) {
		return '';
	}

	const opts = {
		width: 80, // Default width
		lineBreak: '\n',
		mode: 'soft',
		hangingIndent: '',
		collapseWhitespace: false,
		...options
	};

	let result = '';

	if (opts.mode === 'hard') {
		// Hard wrapping: respect existing line breaks
		if (opts.lineBreak) {
			result = text.split(opts.lineBreak).join(opts.lineBreak);
		} else {
			result = text;
		}
		return result;
	}

	// Soft wrapping logic
	if (opts.width === undefined || opts.width <= 0) {
		// If no width is set, return the text as is (or handle as error, but returning text is safer)
		return text;
	}

	const lines = text.split('\n');
	const wrappedLines: string[] = [];

	for (const line of lines) {
		let currentLine = line;

		// 1. Handle whitespace collapsing (if requested)
		if (opts.collapseWhitespace) {
			currentLine = currentLine.replace(/\s+/g, ' ');
		}

		// 2. Handle line wrapping
		if (currentLine.length > opts.width) {
			// Simple word-based wrapping (ignoring complex hyphenation for this benchmark)
			const words = currentLine.split(/\s+/);
			let wrapped = [];
			let currentSegment = '';

			for (const word of words) {
				if (currentSegment.length === 0) {
					currentSegment = word;
				} else if ((currentSegment + ' ' + word).length <= opts.width) {
					currentSegment += ' ' + word;
				} else {
					wrapped.push(currentSegment);
					currentSegment = word;
				}
			}
			if (currentSegment.length > 0) {
				wrapped.push(currentSegment);
			}
			currentLine = wrapped.join(' ');
		}

		// 3. Apply hanging indent
		if (opts.hangingIndent) {
			// Note: Hanging indent is typically applied to subsequent lines, not the first one.
			// We apply it here to the wrapped line.
			currentLine = opts.hangingIndent + currentLine;
		}

		wrappedLines.push(currentLine);
	}

	result = wrappedLines.join(opts.lineBreak);

	return result;
}

